"use strict";(globalThis.webpackChunklearnalgorithms=globalThis.webpackChunklearnalgorithms||[]).push([[5949],{9229(e){e.exports=JSON.parse('{"version":{"pluginId":"default","version":"current","label":"Next","banner":null,"badge":false,"noIndex":false,"className":"docs-version-current","isLast":true,"docsSidebars":{"tutorialSidebar":[{"type":"link","href":"/concepts/","label":"Course Overview","docId":"index","unlisted":false},{"type":"category","label":"1. Foundations","collapsible":true,"collapsed":true,"items":[{"type":"link","href":"/concepts/foundations/algorithmic-thinking","label":"Algorithmic Thinking","docId":"foundations/algorithmic-thinking","unlisted":false},{"type":"link","href":"/concepts/foundations/case-study-pairwise","label":"Case Study - Pairwise Product","docId":"foundations/case-study-pairwise","unlisted":false},{"type":"link","href":"/concepts/foundations/complexity-analysis","label":"Complexity Analysis","docId":"foundations/complexity-analysis","unlisted":false},{"type":"link","href":"/concepts/foundations/asymptotic-notation","label":"Asymptotic Notation","docId":"foundations/asymptotic-notation","unlisted":false},{"type":"link","href":"/concepts/foundations/searching-case-studies","label":"Searching Case Studies","docId":"foundations/searching-case-studies","unlisted":false}],"href":"/concepts/category/1-foundations"},{"type":"category","label":"2. Foundamental Problem Domains","collapsible":true,"collapsed":true,"items":[{"type":"link","href":"/concepts/foundamental-problem-domains/sorting","label":"Foundational Sorting Algorithms","docId":"foundamental-problem-domains/sorting","unlisted":false}],"href":"/concepts/category/2-foundamental-problem-domains"},{"type":"category","label":"3. Algorithm Design Paradigms","collapsible":true,"collapsed":true,"items":[{"type":"link","href":"/concepts/algorithm-design-paradigms/brute-force","label":"Brute Force & Exhaustive Search","docId":"algorithm-design-paradigms/brute-force","unlisted":false},{"type":"link","href":"/concepts/algorithm-design-paradigms/divide-and-conquer","label":"Divide and Conquer","docId":"algorithm-design-paradigms/divide-and-conquer","unlisted":false},{"type":"link","href":"/concepts/algorithm-design-paradigms/greedy-algorithms","label":"Greedy Algorithms","docId":"algorithm-design-paradigms/greedy-algorithms","unlisted":false},{"type":"link","href":"/concepts/algorithm-design-paradigms/dynamic-programming","label":"Dynamic Programming","docId":"algorithm-design-paradigms/dynamic-programming","unlisted":false}],"href":"/concepts/category/3-algorithm-design-paradigms"},{"type":"category","label":"4. State Space Search and Optimization","collapsible":true,"collapsed":true,"items":[{"type":"link","href":"/concepts/state-space-search-and-optimization/backtracking","label":"Introduction to Backtracking","docId":"state-space-search-and-optimization/backtracking","unlisted":false},{"type":"link","href":"/concepts/state-space-search-and-optimization/branch-and-bound","label":"Branch and Bound","docId":"state-space-search-and-optimization/branch-and-bound","unlisted":false}],"href":"/concepts/category/4-state-space-search-and-optimization"},{"type":"category","label":"5. Advanced Execution Models","collapsible":true,"collapsed":true,"items":[{"type":"link","href":"/concepts/advanced-execution-models/parallel-algorithms","label":"Parallel Algorithms & Frameworks","docId":"advanced-execution-models/parallel-algorithms","unlisted":false}],"href":"/concepts/category/5-advanced-execution-models"},{"type":"link","href":"/concepts/glossary","label":"Glossary","docId":"glossary","unlisted":false}]},"docs":{"advanced-execution-models/parallel-algorithms":{"id":"advanced-execution-models/parallel-algorithms","title":"Parallel Algorithms & Frameworks","description":"Up to this point in our computer science curriculum, we have evaluated computational strategies under a sequential execution model, assuming a single central processing unit (CPU) running one machine instruction at a time. However, modern hardware architectures scale processing power by adding physical compute cores rather than raw clock speed.","sidebar":"tutorialSidebar"},"algorithm-design-paradigms/brute-force":{"id":"algorithm-design-paradigms/brute-force","title":"Brute Force & Exhaustive Search","description":"When facing a novel computational problem, our immediate priority as engineers is not performance, but correctness. Before we can optimize a solution, we must prove that the problem is solvable.","sidebar":"tutorialSidebar"},"algorithm-design-paradigms/divide-and-conquer":{"id":"algorithm-design-paradigms/divide-and-conquer","title":"Divide and Conquer","description":"The Divide and Conquer (D&C) paradigm represents one of the most powerful systemic strategies in algorithm design[cite 11]. It fundamentally shifts execution from complex global management to localized resolution and structural combination[cite: 11, 15].","sidebar":"tutorialSidebar"},"algorithm-design-paradigms/dynamic-programming":{"id":"algorithm-design-paradigms/dynamic-programming","title":"Dynamic Programming","description":"The Dynamic Programming (DP) paradigm stands as one of the most advanced and elegant optimization frameworks in Computer Science. Its core engineering philosophy can be summarized by a classic software axiom: those who cannot remember the past are condemned to repeat it.","sidebar":"tutorialSidebar"},"algorithm-design-paradigms/greedy-algorithms":{"id":"algorithm-design-paradigms/greedy-algorithms","title":"Greedy Algorithms","description":"Unlike general programming strategies that explore multiple alternative paths, Greedy Algorithms are designed strictly for optimization problems where the goal is to maximize or minimize a specific objective function.","sidebar":"tutorialSidebar"},"foundamental-problem-domains/sorting":{"id":"foundamental-problem-domains/sorting","title":"Foundational Sorting Algorithms","description":"Sorting is one of the most thoroughly studied problems in Computer Science[cite 9].","sidebar":"tutorialSidebar"},"foundations/algorithmic-thinking":{"id":"foundations/algorithmic-thinking","title":"Algorithmic Thinking","description":"In computational sciences, programming syntax is merely a vehicle for execution. The true engineering core lies in Algorithmics\xe2\u20ac\u201dthe systematic study, design, and analysis of robust and efficient computational strategies.","sidebar":"tutorialSidebar"},"foundations/asymptotic-notation":{"id":"foundations/asymptotic-notation","title":"Asymptotic Notation","description":"In the previous section, we calculated the exact polynomial execution time of a function, such as $T(n) = 3n + 4$. While mathematically precise, dealing with exact polynomials becomes impossible as software architectures grow to millions of lines of code.","sidebar":"tutorialSidebar"},"foundations/case-study-pairwise":{"id":"foundations/case-study-pairwise","title":"Case Study - Pairwise Product","description":"To truly understand why Algorithmics is critical, we must experience failure. In this case study, we will take a deceptively simple problem and attempt to solve it.","sidebar":"tutorialSidebar"},"foundations/complexity-analysis":{"id":"foundations/complexity-analysis","title":"Complexity Analysis","description":"In the previous case study, we saw how an optimal strategy drastically outperformed a brute-force approach. But how do we formalize this comparison?","sidebar":"tutorialSidebar"},"foundations/searching-case-studies":{"id":"foundations/searching-case-studies","title":"Searching Case Studies","description":"We have established the mathematical foundations of complexity analysis and asymptotic notation. Now, we will apply these engineering principles to one of the most fundamental operations in computer science: Information Retrieval (Searching).","sidebar":"tutorialSidebar"},"glossary":{"id":"glossary","title":"Glossary","description":"All concepts defined on this site, grouped by category. Each entry links to its full explanation page.","sidebar":"tutorialSidebar"},"index":{"id":"index","title":"Course Overview","description":"Theoretical foundations and design paradigms behind algorithms and data structures.","sidebar":"tutorialSidebar"},"state-space-search-and-optimization/backtracking":{"id":"state-space-search-and-optimization/backtracking","title":"Introduction to Backtracking","description":"In algorithm design, brute force or exhaustive search should not be used unless absolutely necessary[cite the Magic Square[cite 11]. The objective is to arrange the numbers such that the sum of each individual row, column, and corner-to-corner diagonal matches exactly[cite: 12].","sidebar":"tutorialSidebar"},"state-space-search-and-optimization/branch-and-bound":{"id":"state-space-search-and-optimization/branch-and-bound","title":"Branch and Bound","description":"When solving hard combinatorial problems, Backtracking provides an exact solution by executing a systematic Depth-First Search (DFS). However, it does so blindly, relying entirely on hitting an unfeasible boundary before turning around.","sidebar":"tutorialSidebar"}}}}')}}]);